const calculateTextEntropy = (text) => {
  if (!text || typeof text !== 'string') return 0;
  const cleanText = text.toLowerCase().replace(/[^\w\s]|_/g, "").replace(/\s+/g, " ").trim();
  const tokens = cleanText.split(" ");
  if (tokens.length === 0 || (tokens.length === 1 && !tokens[0])) return 0;
  const uniqueTokens = new Set(tokens);
  return uniqueTokens.size / tokens.length;
};
const validateDraftQuality = (text) => {
  if (!text || text.trim().length < 20) {
      return { isValid: false, error: "Submission is too short." };
  }
  const entropy = calculateTextEntropy(text);
  if (entropy < 0.4) {
      return { isValid: false, error: "Text appears too repetitive or spammy." };
  }
  return { isValid: true, error: null };
};
const getAssetManifest = (historyItems) => {
    const assets = historyItems.filter(h =>
        !['lesson-plan', 'udl-advice', 'alignment-report', 'gemini-bridge'].includes(h.type)
    );
    if (assets.length === 0) return "No specific assets generated yet. Suggest general activities.";
    let manifest = "--- AVAILABLE ASSET INVENTORY (THE KIT) ---\n";
    assets.forEach(item => {
        const title = item.title || "Untitled Resource";
        let usage = "";
        switch(item.type) {
            case 'image': usage = "(Visual Anchor / Hook)"; break;
            case 'adventure': usage = "(Engagement / Hook / Application)"; break;
            case 'simplified': usage = "(Core Text / Direct Instruction)"; break;
            case 'glossary': usage = "(Vocabulary Support)"; break;
            case 'timeline': usage = "(Sequence Activity / Guided Practice)"; break;
            case 'concept-sort': usage = "(Categorization Activity / Guided Practice)"; break;
            case 'sentence-frames': usage = "(Writing Support / Independent Practice)"; break;
            case 'dbq': usage = "(Document Analysis / Critical Thinking)"; break;
            case 'storyforge-config': usage = "(Creative Writing Assignment)"; break;
            case 'storyforge-submission': usage = "(Student Story Submission)"; break;
            case 'quiz': usage = "(Assessment / Closure)"; break;
            case 'math': usage = "(STEM Problem Solving)"; break;
            case 'persona': usage = "(Historical Interview Activity)"; break;
            case 'word_families': {
                const targetWord = currentWordSoundsWord?.toLowerCase() || '';
                const aiRimeData = wordSoundsPhonemes?.rimeFamilyMembers;
                let targetRime = null;
                let familyMembers = [];
                if (aiRimeData && aiRimeData.rime && aiRimeData.words && aiRimeData.words.length >= 3) {
                    targetRime = aiRimeData.rime.replace(/^-/, '');
                    familyMembers = aiRimeData.words
                        .map(w => w.toLowerCase().trim())
                        .filter(w => w && w !== targetWord);
                    debugLog("\u{1F3E0} Using AI-generated rime family:", targetRime, familyMembers);
                }
                if (!targetRime || familyMembers.length < 2) {
                    for (const [rime, members] of Object.entries(RIME_FAMILIES)) {
                        if (targetWord.endsWith(rime) && targetWord.length > rime.length) {
                            targetRime = rime;
                            familyMembers = members.filter(w => w !== targetWord);
                            break;
                        }
                    }
                }
                if (!targetRime) {
                    const ending = targetWord.slice(-2);
                    if (RIME_FAMILIES[ending]) {
                        targetRime = ending;
                        familyMembers = RIME_FAMILIES[ending].filter(w => w !== targetWord);
                    }
                }
                if (!targetRime) {
                    targetRime = 'at';
                    familyMembers = RIME_FAMILIES['at'].filter(w => w !== targetWord);
                    warnLog(`No rime family found for "${targetWord}", falling back to -at`);
                }
                const rimeWordLen = targetWord.length;
                const rimeDifficulty = rimeWordLen <= 3 ? 'easy' : rimeWordLen <= 4 ? 'medium' : 'hard';
                const rimeMemberLimit = rimeDifficulty === 'easy' ? 3 : rimeDifficulty === 'medium' ? 4 : 5;
                const rimeDistractorLimit = rimeDifficulty === 'easy' ? 2 : rimeDifficulty === 'medium' ? 3 : 4;
                const wfSeed = targetWord.split('').reduce((acc, ch) => acc + ch.charCodeAt(0), 0) * 17;
                const wfRng = ((s) => { let x = s; return () => { x = Math.sin(x) * 10000; return x - Math.floor(x); }; })(wfSeed);
                const wfShuffle = (arr) => [...arr].sort(() => wfRng() - 0.5);
                const selectedMembers = wfShuffle(familyMembers).slice(0, rimeMemberLimit);
                const rimeKeys = Object.keys(RIME_FAMILIES);
                const currentRimeIdx = rimeKeys.indexOf(targetRime);
                const adjacentRimes = rimeKeys.filter(r => r !== targetRime && (
                    r[0] === targetRime[0] ||
                    Math.abs(rimeKeys.indexOf(r) - currentRimeIdx) <= 3
                ));
                let distractorPool = [];
                for (const adjRime of wfShuffle(adjacentRimes).slice(0, 4)) {
                    const adjMembers = RIME_FAMILIES[adjRime] || [];
                    distractorPool.push(...adjMembers.slice(0, 3));
                }
                distractorPool = distractorPool.filter(w => !w.endsWith(targetRime));
                const selectedDistractors = wfShuffle(distractorPool).slice(0, rimeDistractorLimit);
                return (
                    <div className="space-y-4">
                    {renderPrompt()}
                    <WordFamiliesView
                        key={`wf-${targetWord}`}
                        data={{
                            family: `-${targetRime} family`,
                            mode: 'rime',
                            difficulty: rimeDifficulty,
                            targetChar: targetRime,
                            targetWord: targetWord,
                            options: selectedMembers,
                            distractors: selectedDistractors
                        }}
                        isEditing={isEditing}
                        onCheckAnswer={(result) => checkAnswer(result === 'correct' ? currentWordSoundsWord : null, currentWordSoundsWord)}
                        onPlayAudio={(w) => handleAudio(w)}
                        onUpdateOption={handleOptionUpdate}
                    />
                    </div>
                );
            }
            default: usage = "(Supplementary Resource)";
        }
        manifest += `- [${item.type.toUpperCase()}] "${title}" (ID: ${item.id}): ${usage}\n`;
    });
    manifest += "-------------------------------------------\n";
    return manifest;
};
